const NAME = "NAME";
const EMAIL = "EMAIL";
const PASSWORD = "PASSWORD";
const REGISTER = "REGISTER";
const LOGIN = "LOGIN";

type InitialStateType = {
  id: number | null,
  nickName: string,
  email: string,
  password: string,
  isAoth: boolean,
}

const initialState: InitialStateType = {
  id: null,
  nickName: "",
  email: "",
  password: "",
  isAoth: false,
}
const registerReducer = (state = initialState, action: any) => {
  let copy;
  switch (action.type) {
    case NAME: {
      copy = { ...state, nickName: action.nickName };
      return copy;
    }
    case EMAIL: {
      copy = { ...state, email: action.email };
      return copy;
    }
    case PASSWORD: {
      copy = { ...state, password: action.password };
      return copy;
    }
    case REGISTER: {
      copy = { ...initialState };
      return copy;
    }
    case LOGIN: {
      copy = { ...state };
      const { email, password } = state;
      if (email === "" || password === "") {
        return console.log("Поля должны быть заполнены");
      }

      const data = {
        email: email,
        password: password,
      };
      try {
        fetch('http://localhost:5000/api/login', {
          method: 'POST',
          headers: { Accept: "application/json", "Content-Type": "application/json" },
          body: JSON.stringify(data),
          credentials: "include",
        }).then((response) => response.json())
          .then((res) => {
            console.log(res);
            // Handle data
          }).catch((error) => {
            console.error('Error:', error);
          });/*
        if (response.message === undefined) {
          localStorage.setItem("UserData", JSON.stringify(response.userData));
          props.set("Операция прошла успешно");
          dispatch(props.registerActin());
          return;
        }
        props.set(response.message.errors[0]["msg"]);*/
      } catch (error) {
        console.log(error);
      }
      return copy;
    }
    default:
      return state;
  }
};
type loginActionType = {
  type: typeof LOGIN
};
type registerActionType = {
  type: typeof REGISTER
};
type nickNameActinType = {
  type: typeof NAME,
  nickName: string
};
type emailActinType = {
  type: typeof EMAIL,
  email: string
};
type passwordActinType = {
  type: typeof PASSWORD,
  password: string
};
export const registerActin = (): registerActionType => ({ type: REGISTER });
export const loginActin = (): loginActionType => ({ type: LOGIN });
export const nickNameActin = (text: string): nickNameActinType => ({
  type: NAME,
  nickName: text,
});
export const emailActin = (text: string): emailActinType => ({
  type: EMAIL,
  email: text,
});
export const passwordActin = (text: string): passwordActinType => ({
  type: PASSWORD,
  password: text,
});

export default registerReducer;

